// URL-Format: /s-multimedia-elektronik/sonstiges/{slug}/k0c168
// Slugs muessen gueltige Kleinanzeigen-Suchbegriffe sein
const BASE = 'https://www.kleinanzeigen.de/s-multimedia-elektronik/sonstiges/';
const SUFFIX = '/k0c168';

const keywords = [
  // SOLARANLAGE / ALLGEMEIN – vom User bestaetigt
  { keyword: 'Solaranlagen', slug: 'solaranlagen', category: 'solaranlage' },
  { keyword: 'Solarcarport', slug: 'solarcarport', category: 'solaranlage' },
  { keyword: 'Solarzaun', slug: 'solarzaun', category: 'solarzaun' },
  { keyword: 'Solar', slug: 'solar', category: 'solaranlage' },
  // WECHSELRICHTER / BRANDS – vom User bestaetigt
  { keyword: 'Sungrow', slug: 'sungrow', category: 'wechselrichter' },
  { keyword: 'Fronius', slug: 'fronius', category: 'wechselrichter' },
  { keyword: 'SMA', slug: 'sma', category: 'wechselrichter' },
  { keyword: 'Solax', slug: 'solax', category: 'wechselrichter' },
  { keyword: 'Solis', slug: 'solis', category: 'wechselrichter' },
  // SPEICHER / BRANDS
  { keyword: 'Victron Energy', slug: 'victron-energy', category: 'solarspeicher' },
  { keyword: 'Pylontech', slug: 'pylontech', category: 'solarspeicher' },
  // BALKONKRAFTWERK – vom User bestaetigt
  { keyword: 'Anker Solix', slug: 'anker-solix', category: 'balkonkraftwerk' },
  { keyword: 'Anker Smartmeter', slug: 'anker-smartmeter', category: 'balkonkraftwerk' },
  { keyword: 'Anker', slug: 'anker', category: 'balkonkraftwerk' },
];

return keywords.map(k => ({
  json: {
    keyword: k.keyword,
    category: k.category,
    searchUrl: BASE + k.slug + SUFFIX,
  }
}));

function stripTags(raw) {
  let t = '';
  let inTag = false;
  for (let i = 0; i < raw.length; i++) {
    if (raw[i] === '<') { inTag = true; continue; }
    if (raw[i] === '>') { inTag = false; continue; }
    if (!inTag) t += raw[i];
  }
  return t.trim();
}

function extractTitle(html, hrefIdx, relUrl) {
  // Strategie 1: zweites Vorkommen derselben URL (Titel-Link)
  const ctx = html.substring(hrefIdx, Math.min(html.length, hrefIdx + 3000));
  const second = ctx.indexOf('href="' + relUrl + '"', 10);
  if (second !== -1) {
    const gt = ctx.indexOf('>', second);
    const ca = ctx.indexOf('</a>', second);
    if (gt !== -1 && ca !== -1 && ca > gt && ca - gt < 400) {
      const t = stripTags(ctx.substring(gt + 1, ca));
      if (t.length > 3 && t.length < 300) return t;
    }
  }
  // Strategie 2: naechstes <h2 oder <h3 nach dem Link
  for (const tag of ['<h2', '<h3', '<p class="text-module']) {
    const hIdx = ctx.indexOf(tag);
    if (hIdx !== -1) {
      const gt = ctx.indexOf('>', hIdx);
      const close = ctx.indexOf('</' + tag.substring(1).split(' ')[0] + '>', hIdx);
      if (gt !== -1 && close !== -1 && close > gt && close - gt < 400) {
        const t = stripTags(ctx.substring(gt + 1, close));
        if (t.length > 3 && t.length < 300) return t;
      }
    }
  }
  // Strategie 3: erstes Anker-Text direkt am Link
  const gt = html.indexOf('>', hrefIdx);
  const ca = html.indexOf('</a>', hrefIdx);
  if (gt !== -1 && ca !== -1 && ca - gt < 400) {
    const t = stripTags(html.substring(gt + 1, ca));
    if (t.length > 3 && t.length < 300) return t;
  }
  return null;
}

function extractPrice(ctx) {
  const euro = '\u20ac';
  const idx = ctx.indexOf(euro);
  if (idx === -1) return null;
  const snippet = ctx.substring(Math.max(0, idx - 15), idx + 4).trim();
  return snippet.length > 1 && snippet.length < 30 ? snippet : null;
}

function parseKleinanzeigenHtml(html) {
  const listings = [];
  const seen = new Set();
  const hrefSearch = 'href="/s-anzeige/';
  let pos = 0;

  while (pos < html.length && listings.length < 25) {
    const hrefIdx = html.indexOf(hrefSearch, pos);
    if (hrefIdx === -1) break;

    const urlStart = hrefIdx + 6;
    const urlEnd = html.indexOf('"', urlStart);
    if (urlEnd === -1) { pos = hrefIdx + 1; continue; }

    const relUrl = html.substring(urlStart, urlEnd);
    pos = urlEnd + 1;

    const segs = relUrl.split('/');
    const lastSeg = segs[segs.length - 1];
    const adId = lastSeg.split('-')[0];

    if (adId.length < 9 || adId.length > 13) continue;
    let isNum = true;
    for (let i = 0; i < adId.length; i++) {
      const c = adId.charCodeAt(i);
      if (c < 48 || c > 57) { isNum = false; break; }
    }
    if (!isNum || seen.has(adId)) continue;
    seen.add(adId);

    const url = 'https://www.kleinanzeigen.de' + relUrl;
    // Titel: aus HTML oder URL-Slug
    let title = extractTitle(html, hrefIdx, relUrl);
    if (!title) {
      const titleSlug = segs.length >= 3 ? segs[segs.length - 2] : '';
      if (titleSlug && titleSlug.length > 3) {
        title = titleSlug.replace(/-/g, ' ');
        title = title.charAt(0).toUpperCase() + title.slice(1);
      } else {
        title = 'Anzeige ' + adId;
      }
    }
    const ctx = html.substring(hrefIdx, Math.min(html.length, hrefIdx + 2000));
    const price = extractPrice(ctx);

    listings.push({
      adId, title, price: price || null,
      description: null, location: null, plz: null,
      date: null, url, image: null, shipping: null,
    });
  }

  return listings;
}

const keywordItems = $('Keywords laden').all();
const htmlItems = $input.all();
const results = [];

for (let i = 0; i < htmlItems.length; i++) {
  const kwItem = keywordItems[i];
  const keyword = kwItem ? kwItem.json.keyword : 'unknown';
  const category = kwItem ? kwItem.json.category : '';
  const htmlJson = htmlItems[i].json;
  const html = String(htmlJson.data || htmlJson || '');
  const listings = parseKleinanzeigenHtml(html);
  results.push({
    json: {
      source: 'kleinanzeigen',
      keyword,
      category,
      listingCount: listings.length,
      listings,
    }
  });
}

return results;
